// ═══════════════════════════════════════════════════════════════
//  CRYPTO SIGNAL ANALYSIS ENGINE v2.0 — n8n Code Node
// ═══════════════════════════════════════════════════════════════

// ─── AYARLAR ───
const COINS = [
  'BTC/USDT', 'AVAX/USDT', 'XRP/USDT', 'KITE/USDT', 'ETH/USDT', 'DOGE/USDT', 'ONT/USDT', 'PEPE/USDT', 'FLOKI/USDT', 'FET/USDT', 'RDNT/USDT', 'PUMP/USDT', 'ARB/USDT', 'APT/USDT', 'LINEA/USDT', 'STRK/USDT', 'BONK/USDT', 'FIL/USDT', 'TRUMP/USDT', 'CHZ/USDT', 'SOL/USDT', 'GLM/USDT', 'API3/USDT', 'SUPER/USDT', 'SHIB/USDT', 'VIRTUAL/USDT', 'MANTA/USDT', 'SNX/USDT', 'TRX/USDT', 'LTC/USDT', 'OGN/USDT', 'XCN/USDT', 'MAGIC/USDT', 'SUI/USDT', 'WLD/USDT', 'ENJ/USDT', 'LRC/USDT', 'EIGEN/USDT', 'AIXBT/USDT', 'TIA/USDT', 'ENA/USDT', 'ZRO/USDT', 'AUDIO/USDT', 'LINK/USDT', 'ETHFI/USDT', 'PNUT/USDT', 'STG/USDT', 'DYDX/USDT', 'GALA/USDT', 'NMR/USDT', 'TURBO/USDT', 'OP/USDT', 'UNI/USDT'
];

const BINANCE_URL = 'https://api.binance.com';
const CANDLE_LIMIT = 300;


// ═══════════════════════════════════════
//  VERİ ÇEKME — n8n uyumlu ($http)
// ═══════════════════════════════════════

async function fetchOHLCV(symbol, interval, limit) {
  const s = symbol.replace('/', '');
  const url = `${BINANCE_URL}/api/v3/klines?symbol=${s}&interval=${interval}&limit=${limit || CANDLE_LIMIT}`;

  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: url,
    json: true,
  });

  const opens = [], highs = [], lows = [], closes = [], volumes = [];
  for (const c of response) {
    opens.push(parseFloat(c[1]));
    highs.push(parseFloat(c[2]));
    lows.push(parseFloat(c[3]));
    closes.push(parseFloat(c[4]));
    volumes.push(parseFloat(c[5]));
  }
  return { opens, highs, lows, closes, volumes };
}


// ═══════════════════════════════════════
//  GÖSTERGE HESAPLAMALARI
// ═══════════════════════════════════════

function round8(v) { return Math.round(v * 1e8) / 1e8; }

function calculateSMA(data, period) {
  if (!data || data.length < period) return null;
  return data.slice(data.length - period).reduce((a, b) => a + b, 0) / period;
}

function calculateEMA(data, period) {
  if (!data || data.length < period) return null;
  const k = 2 / (period + 1);
  let ema = 0;
  for (let i = 0; i < period; i++) ema += data[i];
  ema /= period;
  for (let i = period; i < data.length; i++) ema = (data[i] - ema) * k + ema;
  return ema;
}

function calculateEMASeries(data, period) {
  if (!data || data.length < period) return Array(data ? data.length : 0).fill(null);
  const k = 2 / (period + 1);
  const result = Array(period - 1).fill(null);
  let ema = 0;
  for (let i = 0; i < period; i++) ema += data[i];
  ema /= period;
  result.push(ema);
  for (let i = period; i < data.length; i++) {
    ema = (data[i] - ema) * k + ema;
    result.push(ema);
  }
  return result;
}

function calculateRSI(closes, period) {
  period = period || 14;
  if (!closes || closes.length < period + 1) return { value: null, direction: 'NEUTRAL' };
  const changes = [];
  for (let i = 1; i < closes.length; i++) changes.push(closes[i] - closes[i - 1]);
  const gains = changes.map(c => c > 0 ? c : 0);
  const losses = changes.map(c => c < 0 ? Math.abs(c) : 0);
  let avgGain = 0, avgLoss = 0;
  for (let i = 0; i < period; i++) { avgGain += gains[i]; avgLoss += losses[i]; }
  avgGain /= period; avgLoss /= period;
  let prevRSI = null;
  for (let i = period; i < changes.length; i++) {
    avgGain = (avgGain * (period - 1) + gains[i]) / period;
    avgLoss = (avgLoss * (period - 1) + losses[i]) / period;
    if (i === changes.length - 2) {
      prevRSI = avgLoss === 0 ? 100 : 100 - (100 / (1 + avgGain / avgLoss));
    }
  }
  if (avgLoss === 0) return { value: 100, direction: 'UP' };
  const currentRSI = Math.round((100 - 100 / (1 + avgGain / avgLoss)) * 100) / 100;
  let direction = 'NEUTRAL';
  if (prevRSI !== null) {
    if (currentRSI > prevRSI + 1) direction = 'UP';
    else if (currentRSI < prevRSI - 1) direction = 'DOWN';
  }
  return { value: currentRSI, direction };
}

function calculateMACD(closes) {
  const empty = { macdLine: null, signalLine: null, histogram: null, crossover: 'NONE', momentum: 'NEUTRAL' };
  if (!closes || closes.length < 35) return empty;
  const emaFast = calculateEMASeries(closes, 12);
  const emaSlow = calculateEMASeries(closes, 26);
  const macdLine = [];
  for (let i = 0; i < closes.length; i++) {
    if (emaFast[i] !== null && emaSlow[i] !== null) macdLine.push(emaFast[i] - emaSlow[i]);
    else macdLine.push(null);
  }
  const macdValues = macdLine.filter(v => v !== null);
  if (macdValues.length < 9) return empty;
  const signalValues = calculateEMASeries(macdValues, 9);
  const len = macdValues.length;
  const lastMacd = macdValues[len - 1];
  const lastSignal = signalValues[signalValues.length - 1];
  const prevMacd = len >= 2 ? macdValues[len - 2] : null;
  const prevSignal = signalValues.length >= 2 ? signalValues[signalValues.length - 2] : null;
  const histogram = lastMacd - lastSignal;
  const prevHistogram = (prevMacd !== null && prevSignal !== null) ? prevMacd - prevSignal : null;
  let crossover = 'NONE';
  if (prevMacd !== null && prevSignal !== null) {
    if (prevMacd <= prevSignal && lastMacd > lastSignal) crossover = 'BULLISH';
    else if (prevMacd >= prevSignal && lastMacd < lastSignal) crossover = 'BEARISH';
  }
  let momentum = 'NEUTRAL';
  if (prevHistogram !== null) {
    if (histogram > 0 && histogram > prevHistogram) momentum = 'BULLISH_GROWING';
    else if (histogram > 0 && histogram < prevHistogram) momentum = 'BULLISH_SHRINKING';
    else if (histogram < 0 && histogram < prevHistogram) momentum = 'BEARISH_GROWING';
    else if (histogram < 0 && histogram > prevHistogram) momentum = 'BEARISH_SHRINKING';
  }
  return { macdLine: round8(lastMacd), signalLine: round8(lastSignal), histogram: round8(histogram), crossover, momentum };
}

function calculateADX(highs, lows, closes) {
  const period = 14;
  const empty = { adx: null, plusDi: null, minusDi: null };
  if (!highs || highs.length < period * 2 + 1) return empty;
  const trs = [], pDMs = [], mDMs = [];
  for (let i = 1; i < highs.length; i++) {
    trs.push(Math.max(highs[i] - lows[i], Math.abs(highs[i] - closes[i-1]), Math.abs(lows[i] - closes[i-1])));
    const up = highs[i] - highs[i-1], down = lows[i-1] - lows[i];
    pDMs.push(up > down && up > 0 ? up : 0);
    mDMs.push(down > up && down > 0 ? down : 0);
  }
  let sTR = 0, sPDM = 0, sMDM = 0;
  for (let i = 0; i < period; i++) { sTR += trs[i]; sPDM += pDMs[i]; sMDM += mDMs[i]; }
  const dxValues = [];
  let plusDi = sTR ? 100 * sPDM / sTR : 0;
  let minusDi = sTR ? 100 * sMDM / sTR : 0;
  let diSum = plusDi + minusDi;
  dxValues.push(diSum ? 100 * Math.abs(plusDi - minusDi) / diSum : 0);
  for (let i = period; i < trs.length; i++) {
    sTR = sTR - sTR / period + trs[i];
    sPDM = sPDM - sPDM / period + pDMs[i];
    sMDM = sMDM - sMDM / period + mDMs[i];
    plusDi = sTR ? 100 * sPDM / sTR : 0;
    minusDi = sTR ? 100 * sMDM / sTR : 0;
    diSum = plusDi + minusDi;
    dxValues.push(diSum ? 100 * Math.abs(plusDi - minusDi) / diSum : 0);
  }
  if (dxValues.length < period) return empty;
  let adx = 0;
  for (let i = 0; i < period; i++) adx += dxValues[i];
  adx /= period;
  for (let i = period; i < dxValues.length; i++) adx = (adx * (period - 1) + dxValues[i]) / period;
  return { adx: Math.round(adx * 100) / 100, plusDi: Math.round(plusDi * 100) / 100, minusDi: Math.round(minusDi * 100) / 100 };
}

function calculateATR(highs, lows, closes) {
  const period = 14;
  if (!highs || highs.length < period + 1) return null;
  const trs = [];
  for (let i = 1; i < highs.length; i++)
    trs.push(Math.max(highs[i] - lows[i], Math.abs(highs[i] - closes[i-1]), Math.abs(lows[i] - closes[i-1])));
  let atr = 0;
  for (let i = 0; i < period; i++) atr += trs[i];
  atr /= period;
  for (let i = period; i < trs.length; i++) atr = (atr * (period - 1) + trs[i]) / period;
  return round8(atr);
}

function calculateBB(closes) {
  const period = 20, mult = 2;
  if (!closes || closes.length < period) return { upper: null, middle: null, lower: null, position: null };
  const slice = closes.slice(closes.length - period);
  const middle = slice.reduce((a, b) => a + b, 0) / period;
  const stdDev = Math.sqrt(slice.reduce((a, v) => a + Math.pow(v - middle, 2), 0) / period);
  const upper = middle + mult * stdDev, lower = middle - mult * stdDev;
  const bw = upper - lower;
  const position = bw ? (closes[closes.length - 1] - lower) / bw : 0.5;
  return { upper: round8(upper), middle: round8(middle), lower: round8(lower), position: Math.round(position * 1e4) / 1e4 };
}

function calculateVolume(volumes) {
  const period = 20;
  if (!volumes || volumes.length < period) return { ratio: null, signal: 'NEUTRAL' };
  const current = volumes[volumes.length - 1];
  const ma = calculateSMA(volumes, period);
  if (!ma) return { ratio: null, signal: 'NEUTRAL' };
  const ratio = current / ma;
  let signal = 'NEUTRAL';
  if (ratio >= 2) signal = 'VERY_HIGH';
  else if (ratio >= 1.5) signal = 'HIGH';
  else if (ratio >= 1) signal = 'NORMAL';
  else if (ratio >= 0.5) signal = 'LOW';
  else signal = 'VERY_LOW';
  return { ratio: Math.round(ratio * 1e4) / 1e4, signal };
}

function calculateEMA200(closes) {
  const ema200 = calculateEMA(closes, 200);
  if (!ema200) return { ema200: null, trend: 'UNKNOWN', distance: null };
  const price = closes[closes.length - 1];
  const distance = ((price - ema200) / ema200) * 100;
  return {
    ema200: round8(ema200),
    trend: price > ema200 ? 'BULLISH' : price < ema200 ? 'BEARISH' : 'NEUTRAL',
    distance: Math.round(distance * 100) / 100,
  };
}

function calculateEMACross(closes) {
  if (!closes || closes.length < 202) return { cross: 'NONE', ema50: null };
  const ema50s = calculateEMASeries(closes, 50);
  const ema200s = calculateEMASeries(closes, 200);
  const len = closes.length;
  const c50 = ema50s[len-1], c200 = ema200s[len-1];
  const p50 = ema50s[len-2], p200 = ema200s[len-2];
  if (!c50 || !c200 || !p50 || !p200) return { cross: 'NONE', ema50: c50 };
  let cross = 'NONE';
  if (p50 <= p200 && c50 > c200) cross = 'GOLDEN';
  else if (p50 >= p200 && c50 < c200) cross = 'DEATH';
  else if (c50 > c200) cross = 'ABOVE';
  else cross = 'BELOW';
  return { cross, ema50: round8(c50) };
}


// ═══════════════════════════════════════
//  ANALİZ + PUANLAMA + SİNYAL
// ═══════════════════════════════════════

function analyze(ohlcv, symbol, tf) {
  const { opens, highs, lows, closes, volumes } = ohlcv;
  if (!closes || closes.length < 200) return null;

  const price = closes[closes.length - 1];
  const open = opens[opens.length - 1];
  const candle = price > open ? 'GREEN' : price < open ? 'RED' : 'DOJI';

  const rsiData = calculateRSI(closes);
  const rsi = rsiData.value;
  const rsiDir = rsiData.direction;
  const macd = calculateMACD(closes);
  const ema200 = calculateEMA200(closes);
  const emaCross = calculateEMACross(closes);
  const adx = calculateADX(highs, lows, closes);
  const atr = calculateATR(highs, lows, closes);
  const vol = calculateVolume(volumes);
  const bb = calculateBB(closes);

  // RSI Skor
  let rsiSignal = 'NEUTRAL', rsiScore = 0;
  if (rsi !== null) {
    if (rsi <= 20) { rsiSignal = 'EXTREMELY_OVERSOLD'; rsiScore = 3; }
    else if (rsi <= 30) { rsiSignal = 'OVERSOLD'; rsiScore = 2; }
    else if (rsi <= 40) { rsiSignal = 'SLIGHTLY_OVERSOLD'; rsiScore = 1; }
    else if (rsi >= 80) { rsiSignal = 'EXTREMELY_OVERBOUGHT'; rsiScore = -3; }
    else if (rsi >= 70) { rsiSignal = 'OVERBOUGHT'; rsiScore = -2; }
    else if (rsi >= 60) { rsiSignal = 'SLIGHTLY_OVERBOUGHT'; rsiScore = -1; }
    if (rsi <= 35 && rsiDir === 'UP') rsiScore += 1;
    if (rsi >= 65 && rsiDir === 'DOWN') rsiScore -= 1;
  }

  // MACD Skor
  let macdScore = 0;
  if (macd.histogram !== null) {
    if (macd.crossover === 'BULLISH') macdScore = 3;
    else if (macd.crossover === 'BEARISH') macdScore = -3;
    else if (macd.histogram > 0 && macd.macdLine > 0) macdScore = 2;
    else if (macd.histogram > 0) macdScore = 1;
    else if (macd.histogram < 0 && macd.macdLine < 0) macdScore = -2;
    else if (macd.histogram < 0) macdScore = -1;
    if (macd.momentum === 'BULLISH_GROWING') macdScore += 1;
    else if (macd.momentum === 'BEARISH_GROWING') macdScore -= 1;
    else if (macd.momentum === 'BULLISH_SHRINKING' && macdScore > 0) macdScore -= 1;
    else if (macd.momentum === 'BEARISH_SHRINKING' && macdScore < 0) macdScore += 1;
  }

  // EMA Skorlar
  let ema200Score = 0;
  if (ema200.trend === 'BULLISH') { ema200Score = 2; if (ema200.distance > 5) ema200Score = 1; }
  else if (ema200.trend === 'BEARISH') { ema200Score = -2; if (ema200.distance < -5) ema200Score = -1; }

  let emaCrossScore = 0;
  if (emaCross.cross === 'GOLDEN') emaCrossScore = 2;
  else if (emaCross.cross === 'DEATH') emaCrossScore = -2;
  else if (emaCross.cross === 'ABOVE') emaCrossScore = 1;
  else if (emaCross.cross === 'BELOW') emaCrossScore = -1;

  // ADX Skor
  let adxSignal = 'WEAK_TREND', adxScore = 0;
  if (adx.adx !== null) {
    if (adx.adx >= 50) adxSignal = 'VERY_STRONG_TREND';
    else if (adx.adx >= 25) adxSignal = 'STRONG_TREND';
    else if (adx.adx >= 20) adxSignal = 'MODERATE_TREND';
    if (adx.adx >= 25) adxScore = adx.plusDi > adx.minusDi ? 2 : -2;
    else if (adx.adx >= 20) adxScore = adx.plusDi > adx.minusDi ? 1 : -1;
  }

  // BB Skor
  let bbSignal = 'NEUTRAL', bbScore = 0;
  if (bb.position !== null) {
    if (bb.position <= 0) { bbSignal = 'BELOW_LOWER'; bbScore = 2; }
    else if (bb.position <= 0.2) { bbSignal = 'NEAR_LOWER'; bbScore = 1; }
    else if (bb.position >= 1) { bbSignal = 'ABOVE_UPPER'; bbScore = -2; }
    else if (bb.position >= 0.8) { bbSignal = 'NEAR_UPPER'; bbScore = -1; }
    else bbSignal = 'MIDDLE';
  }

  // Hacim Skor
  let volScore = 0;
  if (vol.ratio !== null) {
    if (vol.ratio >= 2) { volScore = candle === 'GREEN' ? 2 : candle === 'RED' ? -2 : 0; }
    else if (vol.ratio >= 1.5) { volScore = candle === 'GREEN' ? 1 : candle === 'RED' ? -1 : 0; }
  }

  // Toplam
  const allScores = [rsiScore, macdScore, ema200Score, emaCrossScore, adxScore, bbScore, volScore];
  let buyScore = 0, sellScore = 0;
  for (const s of allScores) { if (s > 0) buyScore += s; if (s < 0) sellScore += Math.abs(s); }

  // Bonus
  let bonus = 0;
  if (macd.crossover === 'BULLISH' && rsi < 50) bonus += 2;
  if (macd.crossover === 'BEARISH' && rsi > 50) bonus -= 2;
  if (ema200.trend === 'BULLISH' && macdScore > 0 && rsiScore > 0) bonus += 2;
  if (ema200.trend === 'BEARISH' && macdScore < 0 && rsiScore < 0) bonus -= 2;
  if (vol.ratio >= 1.5) {
    if (buyScore > sellScore && candle === 'GREEN') bonus += 1;
    if (sellScore > buyScore && candle === 'RED') bonus -= 1;
  }
  if (adx.adx >= 30) {
    if (adx.plusDi > adx.minusDi && buyScore > sellScore) bonus += 1;
    if (adx.minusDi > adx.plusDi && sellScore > buyScore) bonus -= 1;
  }
  if (bb.position <= 0.1 && rsi < 35) bonus += 2;
  if (bb.position >= 0.9 && rsi > 65) bonus -= 2;
  if (emaCross.cross === 'GOLDEN' && ema200.trend === 'BULLISH') bonus += 2;
  if (emaCross.cross === 'DEATH' && ema200.trend === 'BEARISH') bonus -= 2;
  if (rsiDir === 'UP' && candle === 'GREEN' && rsi < 45) bonus += 1;
  if (rsiDir === 'DOWN' && candle === 'RED' && rsi > 55) bonus -= 1;

  const rawScore = buyScore - sellScore + bonus;

  // Sinyal
  let signalType = 'WAIT', dir = 'NEUTRAL';
  if (rawScore >= 8) { signalType = 'STRONG_BUY'; dir = 'BUY'; }
  else if (rawScore >= 5) { signalType = 'BUY'; dir = 'BUY'; }
  else if (rawScore >= 3) { signalType = 'WEAK_BUY'; dir = 'BUY'; }
  else if (rawScore <= -8) { signalType = 'STRONG_SELL'; dir = 'SELL'; }
  else if (rawScore <= -5) { signalType = 'SELL'; dir = 'SELL'; }
  else if (rawScore <= -3) { signalType = 'WEAK_SELL'; dir = 'SELL'; }

  // Filtre
  if (adx.adx !== null && adx.adx < 15) {
    if (signalType === 'STRONG_BUY') signalType = 'WEAK_BUY';
    else if (signalType === 'STRONG_SELL') signalType = 'WEAK_SELL';
    else if (signalType === 'BUY' && rawScore < 6) signalType = 'WEAK_BUY';
    else if (signalType === 'SELL' && rawScore > -6) signalType = 'WEAK_SELL';
  }
  if (vol.ratio !== null && vol.ratio < 0.3 && (signalType === 'WEAK_BUY' || signalType === 'WEAK_SELL')) {
    signalType = 'WAIT'; dir = 'NEUTRAL';
  }
  if (ema200.trend === 'BEARISH' && signalType === 'STRONG_BUY' && adx.adx < 30) signalType = 'BUY';
  if (ema200.trend === 'BULLISH' && signalType === 'STRONG_SELL' && adx.adx < 30) signalType = 'SELL';

  // Güven
  let confidence = Math.min((Math.abs(rawScore) / 20) * 100, 100);
  if (adx.adx >= 30) confidence = Math.min(confidence * 1.15, 100);
  else if (adx.adx < 20) confidence *= 0.8;
  if (vol.ratio >= 1.5) confidence = Math.min(confidence * 1.1, 100);
  else if (vol.ratio < 0.5) confidence *= 0.85;
  if (emaCross.cross === 'GOLDEN' || emaCross.cross === 'DEATH') confidence = Math.min(confidence * 1.1, 100);
  if (dir === 'BUY' && candle === 'GREEN') confidence = Math.min(confidence * 1.05, 100);
  else if (dir === 'SELL' && candle === 'RED') confidence = Math.min(confidence * 1.05, 100);
  else if (dir === 'BUY' && candle === 'RED') confidence *= 0.95;
  else if (dir === 'SELL' && candle === 'GREEN') confidence *= 0.95;
  confidence = Math.round(confidence * 100) / 100;

  // Risk
  let sl = null, tp1 = null, tp2 = null, tp3 = null, rr = null;
  if (atr && price && dir !== 'NEUTRAL') {
    let slM = 1.5;
    if (adx.adx >= 40) slM = 1.2; else if (adx.adx >= 30) slM = 1.3;
    else if (adx.adx >= 25) slM = 1.5; else if (adx.adx >= 20) slM = 1.8; else slM = 2.0;
    let t1M = 1.5, t2M = 2.5, t3M = 4.0;
    if (vol.ratio >= 2) { t1M = 2; t2M = 3.5; t3M = 5; }
    else if (vol.ratio >= 1.5) { t1M = 1.8; t2M = 3; t3M = 4.5; }
    if (dir === 'BUY') { sl = price - atr*slM; tp1 = price + atr*t1M; tp2 = price + atr*t2M; tp3 = price + atr*t3M; }
    else { sl = price + atr*slM; tp1 = price - atr*t1M; tp2 = price - atr*t2M; tp3 = price - atr*t3M; }
    const risk = Math.abs(price - sl), reward = Math.abs(tp1 - price);
    rr = risk ? Math.round(reward / risk * 100) / 100 : null;
    sl = round8(sl); tp1 = round8(tp1); tp2 = round8(tp2); tp3 = round8(tp3);
  }

  return {
    symbol, timeframe: tf, signalType, confidence, currentPrice: price,
    openPrice: open, highPrice: highs[highs.length-1], lowPrice: lows[lows.length-1],
    volume: volumes[volumes.length-1], candleDirection: candle,
    rsi, rsiSignal, rsiDirection: rsiDir,
    macdLine: macd.macdLine, macdSignalLine: macd.signalLine, macdHistogram: macd.histogram,
    macdCrossover: macd.crossover, macdMomentum: macd.momentum,
    ema200: ema200.ema200, priceVsEma200: ema200.trend, ema200Distance: ema200.distance,
    ema50: emaCross.ema50, emaCross: emaCross.cross,
    adx: adx.adx, plusDi: adx.plusDi, minusDi: adx.minusDi, adxSignal,
    atr, atrPercent: atr ? Math.round((atr/price)*10000)/100 : null,
    volumeRatio: vol.ratio, volumeSignal: vol.signal,
    bbUpper: bb.upper, bbMiddle: bb.middle, bbLower: bb.lower, bbPosition: bb.position, bbSignal,
    buyScore, sellScore, bonusScore: bonus, rawScore,
    stopLoss: sl, takeProfit1: tp1, takeProfit2: tp2, takeProfit3: tp3, riskRewardRatio: rr,
  };
}


// ═══════════════════════════════════════
//  MULTI-TIMEFRAME
// ═══════════════════════════════════════

function multiTF(a1h, a4h) {
  if (!a1h) return null;
  function trend(a) {
    let bull = 0, bear = 0;
    if (a.priceVsEma200 === 'BULLISH') bull++; else if (a.priceVsEma200 === 'BEARISH') bear++;
    if (a.macdHistogram > 0) bull++; else if (a.macdHistogram < 0) bear++;
    if (a.rsi > 50) bull++; else if (a.rsi < 50) bear++;
    if (a.plusDi > a.minusDi) bull++; else bear++;
    if (a.emaCross === 'GOLDEN' || a.emaCross === 'ABOVE') bull++;
    else if (a.emaCross === 'DEATH' || a.emaCross === 'BELOW') bear++;
    return bull >= 3 ? 'BULLISH' : bear >= 3 ? 'BEARISH' : 'NEUTRAL';
  }
  const t1h = trend(a1h);
  const t4h = a4h ? trend(a4h) : 'UNKNOWN';
  let alignment = 'MIXED';
  if (t1h === t4h) alignment = 'ALIGNED';
  else if (t1h === 'NEUTRAL' || t4h === 'NEUTRAL' || t4h === 'UNKNOWN') alignment = 'PARTIAL';
  else alignment = 'CONFLICTING';
  let sig = a1h.signalType, conf = a1h.confidence;
  if (alignment === 'ALIGNED') conf = Math.min(conf * 1.2, 100);
  else if (alignment === 'CONFLICTING') {
    conf *= 0.7;
    if (sig === 'STRONG_BUY') sig = 'BUY';
    else if (sig === 'STRONG_SELL') sig = 'SELL';
    else if (sig === 'BUY') sig = 'WEAK_BUY';
    else if (sig === 'SELL') sig = 'WEAK_SELL';
  }
  return { ...a1h, signalType: sig, confidence: Math.round(conf * 100) / 100, trend1h: t1h, trend4h: t4h, trendAlignment: alignment };
}


