const results = [];

for (const symbol of COINS) {
  try {
    const s = symbol.replace('/', '');

    // n8n httpRequest ile veri çek
    const data1hRaw = await this.helpers.httpRequest({
      method: 'GET',
      url: `${BINANCE_URL}/api/v3/klines?symbol=${s}&interval=1h&limit=${CANDLE_LIMIT}`,
      json: true,
    });

    const data4hRaw = await this.helpers.httpRequest({
      method: 'GET',
      url: `${BINANCE_URL}/api/v3/klines?symbol=${s}&interval=4h&limit=${CANDLE_LIMIT}`,
      json: true,
    });

    // Parse et
    function parseCandles(raw) {
      const opens = [], highs = [], lows = [], closes = [], volumes = [];
      for (const c of raw) {
        opens.push(parseFloat(c[1]));
        highs.push(parseFloat(c[2]));
        lows.push(parseFloat(c[3]));
        closes.push(parseFloat(c[4]));
        volumes.push(parseFloat(c[5]));
      }
      return { opens, highs, lows, closes, volumes };
    }

    const data1h = parseCandles(data1hRaw);
    const data4h = parseCandles(data4hRaw);

    const a1h = analyze(data1h, symbol, '1h');
    const a4h = analyze(data4h, symbol, '4h');
    const result = multiTF(a1h, a4h);

    if (result) {
      results.push({ json: result });
    }

    // Rate limit
    await new Promise(r => setTimeout(r, 300));
  } catch (err) {
    results.push({ json: { symbol, error: err.message } });
  }
}

return results;

