  else { adxEmoji = '😴'; adxText = 'Zayıf Trend — Sinyal Güvenilmez'; }

  // DI yönü
  const diEmoji = s.plusDi > s.minusDi ? '🟢 Alıcılar Güçlü' : '🔴 Satıcılar Güçlü';

  // Hacim durumu
  let volEmoji = '⚪';
  let volText = '';
  if (s.volumeRatio >= 2) { volEmoji = '🔊🔊'; volText = 'Çok Yüksek — Büyük Hareket'; }
  else if (s.volumeRatio >= 1.5) { volEmoji = '🔊'; volText = 'Yüksek — İyi Katılım'; }
  else if (s.volumeRatio >= 1) { volEmoji = '🔉'; volText = 'Normal'; }
  else if (s.volumeRatio >= 0.5) { volEmoji = '🔈'; volText = 'Düşük — Dikkat'; }
  else { volEmoji = '🔇'; volText = 'Çok Düşük — Güvenme'; }

  // Bollinger durumu
  let bbEmoji = '⚪';
  if (s.bbSignal === 'BELOW_LOWER' || s.bbSignal === 'NEAR_LOWER') bbEmoji = '🟢';
  else if (s.bbSignal === 'ABOVE_UPPER' || s.bbSignal === 'NEAR_UPPER') bbEmoji = '🔴';

  // EMA Cross
  let crossEmoji = '⚪';
  let crossText = '';
  if (s.emaCross === 'GOLDEN') { crossEmoji = '⭐'; crossText = 'Altın Kesişim — GÜÇLÜ ALIM'; }
  else if (s.emaCross === 'DEATH') { crossEmoji = '💀'; crossText = 'Ölüm Kesişimi — GÜÇLÜ SATIM'; }
  else if (s.emaCross === 'ABOVE') { crossEmoji = '📈'; crossText = 'EMA50 Üstte — Yükseliş'; }
  else if (s.emaCross === 'BELOW') { crossEmoji = '📉'; crossText = 'EMA50 Altta — Düşüş'; }

  // Mum yönü
  const candleEmoji = s.candleDirection === 'GREEN' ? '🟩' : s.candleDirection === 'RED' ? '🟥' : '⬜';

  // Güven barı
  let confBar = '';
  const confPct = Math.round(s.confidence);
  const filled = Math.round(confPct / 10);
  confBar = '█'.repeat(filled) + '░'.repeat(10 - filled) + ` ${confPct}%`;

  // Risk yüzdeleri
  const slPct = s.stopLoss ? (((s.stopLoss - s.currentPrice) / s.currentPrice) * 100).toFixed(2) : '—';
  const tp1Pct = s.takeProfit1 ? (((s.takeProfit1 - s.currentPrice) / s.currentPrice) * 100).toFixed(2) : '—';
  const tp2Pct = s.takeProfit2 ? (((s.takeProfit2 - s.currentPrice) / s.currentPrice) * 100).toFixed(2) : '—';
  const tp3Pct = s.takeProfit3 ? (((s.takeProfit3 - s.currentPrice) / s.currentPrice) * 100).toFixed(2) : '—';

  // Puan barı
  const scoreEmoji = s.rawScore > 0 ? '🟢' : s.rawScore < 0 ? '🔴' : '⚪';

  item.json.telegramMessage = 
`━━━━━━━━━━━━━━━━━━━━━━━
${signalEmoji} ${s.symbol}
━━━━━━━━━━━━━━━━━━━━━━━

${actionText}
💰 Fiyat: $${s.currentPrice}
📊 Güven: ${confBar}
${candleEmoji} Son Mum: ${s.candleDirection}

━━━ 📈 TREND ANALİZİ ━━━

${trend1hEmoji} 1 Saatlik: ${s.trend1h}
${trend4hEmoji} 4 Saatlik: ${s.trend4h}
${alignEmoji} Uyum: ${alignText}

━━━ 🔬 GÖSTERGELER ━━━

${rsiEmoji} RSI: ${s.rsi} ${rsiDirEmoji}
   └─ ${rsiText}

${macdEmoji} MACD: ${macdText}
${momEmoji} Momentum: ${momText}

${adxEmoji} ADX: ${s.adx}
   └─ ${adxText}
   └─ ${diEmoji}
   └─ +DI: ${s.plusDi} / -DI: ${s.minusDi}

${volEmoji} Hacim: ${s.volumeRatio}x
   └─ ${volText}

${bbEmoji} Bollinger: ${s.bbSignal}
   └─ Pozisyon: %${s.bbPosition ? (s.bbPosition * 100).toFixed(1) : '—'}

${crossEmoji} EMA Kesişim: ${crossText}

📏 EMA200: ${s.priceVsEma200} (${s.ema200Distance > 0 ? '+' : ''}${s.ema200Distance}%)

━━━ 🎯 PUANLAMA ━━━

${scoreEmoji} Ham Skor: ${s.rawScore}
🟢 Alış Puanı: ${s.buyScore}
🔴 Satış Puanı: ${s.sellScore}
⭐ Bonus: ${s.bonusScore}

━━━ 🛡️ RİSK YÖNETİMİ ━━━

🔴 Stop Loss: $${s.stopLoss || '—'}
   └─ ${slPct}%

🟢 Hedef 1: $${s.takeProfit1 || '—'}
   └─ +${tp1Pct}%

🟢 Hedef 2: $${s.takeProfit2 || '—'}
   └─ +${tp2Pct}%

🟢 Hedef 3: $${s.takeProfit3 || '—'}
   └─ +${tp3Pct}%

⚖️ Risk/Ödül: 1:${s.riskRewardRatio || '—'}

━━━━━━━━━━━━━━━━━━━━━━━
⏰ ${new Date().toLocaleString('tr-TR')}
🤖 Crypto Signal Bot v2.0
━━━━━━━━━━━━━━━━━━━━━━━`;

  // Telegram özel karakterlerini temizle
item.json.telegramMessage = item.json.telegramMessage
  .replace(/_/g, ' ')
  .replace(/\*/g, '')
  .replace(/\[/g, '(')
  .replace(/\]/g, ')')
  .replace(/~/g, '-')
  .replace(/`/g, "'");

  strongSignals.push(item);
}

// Sinyal yoksa bildir
if (strongSignals.length === 0) {
  strongSignals.push({
    json: {
      telegramMessage: `⚪ Şu an aktif sinyal yok.\n\n⏰ ${new Date().toLocaleString('tr-TR')}\n\nTüm coinler WAIT durumunda.\nBir sonraki analiz 1 saat sonra.`
    }
  });
}

return strongSignals;
